import{_ as r,o as p,c as t,a6 as s,hs as i,ht as o,hu as n,hv as e,hw as l,hx as g,is as m,it as _,eu as c,hy as h,iu as d,iv as f,iw as x,ix as u,iy as b,iz as P,iA as k}from"./chunks/framework.UYVGz2W_.js";const D=JSON.parse('{"title":"メタデータ列","description":"","frontmatter":{},"headers":[],"relativePath":"ja/meta-column/index.md","filePath":"ja/meta-column/index.md"}'),T={name:"ja/meta-column/index.md"};function S($,a,v,A,V,j){return p(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="メタデータ列" tabindex="-1">メタデータ列 <a class="header-anchor" href="#メタデータ列" aria-label="Permalink to “メタデータ列”">​</a></h1><p>一般的なスプレッドシートページにさらに情報を追加するには、<strong>メタデータ列</strong>を作成することができます。</p><p>メタデータ列を使用すると、制作に関連する追加情報を追跡することができます。 例えば、タスクの難易度を追跡するメタデータ列や、タスクの特定の側面を識別するのに役立つカスタムタグを試す列などがあります。 カスタムメタデータ列では、さまざまな形式でデータを保存できるため、データの入力、フィルタリング、検証が容易になります。</p><h2 id="メタデータカラムの作成" tabindex="-1">メタデータカラムの作成 <a class="header-anchor" href="#メタデータカラムの作成" aria-label="Permalink to “メタデータカラムの作成”">​</a></h2><p>新しいカスタムメタデータカラムを追加するには、カラム名の隣にある「+」アイコンをクリックします。</p><p><img src="'+i+'" alt="メタデータカラム"></p><p>まず、フィールドの名前を任意で選択します。次に、ニーズに合わせて適切な<strong>タイプ</strong>を選択します。</p><ul><li><p><strong>テキスト</strong>：</p></li><li><p>このタイプは、文字と数字の両方を含むテキストベースの入力を処理します。説明、コメント、テキストコンテンツなどの情報を柔軟に保存できます。</p></li><li><p><strong>数値</strong>：</p></li><li><p>数値データ専用です。フレームレート、日付、時刻など、数値のみで構成される情報を追跡する場合に推奨されます。</p></li><li><p><strong>チェックボックス</strong>：</p></li><li><p>このオプションでは、項目をオンまたはオフとしてマークすることができます。 例えば、予告編用のカットのショットを指定するなど、2つの状態のみが考えられるデータの追跡に適しています。</p></li><li><p><strong>値のリスト</strong>：</p></li><li><p>このタイプでは、一意の要素を1つだけ選択できるオプションのリストを定義します。選択肢が限られているデータを追跡する際に最適です。例えば、カメラの動きを追跡する場合、「静止」、「パン」、「チルト」、「ズーム」などのオプションが考えられます。</p></li><li><p><strong>タグのリスト</strong>:</p></li><li><p>ここでは、複数のタグを定義できます。1つの項目のみを選択できる値のリストとは異なり、このタイプではリストから複数のエントリを選択できます。</p></li><li><p><strong>チェックリスト</strong>: このタイプでは、オプションのリストが提示され、それぞれにチェックボックスが付いています。 制作パイプラインにおいて独自のタスクとして扱うほどではない、ショットやアセットに関連する細かいサブタスクを追跡するのに便利です。</p></li></ul><p><img src="'+o+'" alt="メタデータカラムの詳細"></p><p>:::警告 テキスト<strong>および</strong>数値**のメタデータタイプを作成する際、作成時にデフォルト値は必要ありません。</p><p>ただし、「<strong>値のリスト</strong>」、「<strong>タグのリスト</strong>」、および「<strong>チェックリスト</strong>」を使用する場合は、作成時に含める値を指定する必要があります。</p><p><img src="'+n+'" alt="メタデータカラムのリスト"></p><p>利用可能な値」の下にリスト要素を入力し、「値を追加」をクリックして確認します。 :::</p><h3 id="メタデータカラムと部門のリンク" tabindex="-1">メタデータカラムと部門のリンク <a class="header-anchor" href="#メタデータカラムと部門のリンク" aria-label="Permalink to “メタデータカラムと部門のリンク”">​</a></h3><p>メタデータカラムを1つまたは複数の部門にリンクすることもできます。アーティスト/スーパーバイザーは、自分のToDoページと部門フィルタリングされたビューでそれを見ることができます。</p><p>部門をさらに作成するには、<a href="./../configure-kitsu/#create-departments">部門の作成</a>を参照してください。</p><p>メタデータ列を1つまたは複数の部門にリンクすることができます。 リストから部門をクリックし、<strong>追加</strong>をクリックして確定します。</p><p>ここでは、VFX列が2つの部門にリンクされています。</p><p><img src="'+e+'" alt="部門メタデータ列のフィルタリングビュー"></p><p>::: 詳細 メタデータカラムの編集方法 アセットまたはショットのグローバルページで、メタデータカラムの右端にある矢印をクリックし、<strong>[編集]</strong>をクリックします。</p><p><img src="'+l+'" alt="メタデータカラムの編集"> :::</p><p>おめでとうございます。新しく作成したメタデータカラムがグローバルページで利用可能になりました。</p><p><img src="'+g+'" alt="メタデータカラムの詳細"></p><p>::: ヒント 一括更新 同じ値で複数のアイテムを更新したい場合は、まず下記のように対象のアイテムをチェックし、その後値を更新します。 入力した値は、すべてのアイテムにわたって更新されます。</p><p><img src="'+m+'" alt="メタデータカラムの詳細"></p><p><img src="'+_+'" alt="メタデータカラムの詳細"></p><p>:::</p><p>::: 詳細 エンティティの編集 スプレッドシート内のエンティティを直接更新することもできますが、編集ボタン <img src="'+c+'" alt="編集ボタン"> を使用して複数のメタデータカラムを更新することもできます。</p><p>選択すると、その特定のエンティティのすべてのメタデータ列の値を入力または調整することができます。作業が完了したら、必ず「確認」ボタンを押してください。</p><p><img src="'+h+'" alt="メタデータ列の詳細"> ::::</p><p>メタデータ列を編集または削除する必要がある場合は、メタデータ列の名前の隣にあるスプレッドシートのページで、矢印をクリックします！<a href="../img/getting-started/arrow.png">メタデータ列の詳細</a>。</p><p>::: ヒント メタデータ列の編集や削除に加えて、ここから<strong>ソート</strong>をクリックして、新しい列でグローバルページを<strong>ソート</strong>することもできます。</p><p>さらに、メタデータ列を<strong>固定</strong>することもできます。つまり、大きなデータセットをスクロールしている間も左側に固定され、表示されたままになります。 :::</p><h2 id="メタデータ列の整理" tabindex="-1">メタデータ列の整理 <a class="header-anchor" href="#メタデータ列の整理" aria-label="Permalink to “メタデータ列の整理”">​</a></h2><h3 id="すべてのメタデータ列の表示または非表示" tabindex="-1">すべてのメタデータ列の表示または非表示 <a class="header-anchor" href="#すべてのメタデータ列の表示または非表示" aria-label="Permalink to “すべてのメタデータ列の表示または非表示”">​</a></h3><p>グローバルスプレッドシートを整理しておくために、必要のない列を非表示にすることができます。この操作は列を削除するものではなく、単に表示を隠すだけで、使用されている他の領域では保持されます。</p><p>これを行うには、ページの右上にある「追加情報の非表示」 <img src="'+d+'" alt="最小化ボタン"> ボタンをクリックします。</p><p><img src="'+f+'" alt="すべての情報を表示"></p><p>情報を再度表示するには、同じボタンをクリックします。 <img src="'+x+'" alt="最大化ボタン"> グレーでハイライトされません。</p><p><img src="'+u+'" alt="すべての情報表示"></p><h3 id="メタデータカラムの表示または非表示" tabindex="-1">メタデータカラムの表示または非表示 <a class="header-anchor" href="#メタデータカラムの表示または非表示" aria-label="Permalink to “メタデータカラムの表示または非表示”">​</a></h3><p>グローバルページ上で特定の<strong>メタデータ列</strong>を非表示または表示する必要がある場合があります。</p><p>メタデータ列を非表示にするには、グローバルページの右端にある矢印をクリックします。</p><p><img src="'+b+'" alt="表示列"></p><p>非表示<strong>または</strong>表示**する列を選択することができます。</p><h2 id="固定コラム" tabindex="-1">固定コラム <a class="header-anchor" href="#固定コラム" aria-label="Permalink to “固定コラム”">​</a></h2><p>参照頻度の高い情報がある場合、そのコラムをショット名の隣に<strong>固定</strong>することができます。</p><p>コラムの右側にある矢印をクリックしてコラムメニューを開き、<strong>固定</strong>を選択します。</p><p><img src="'+P+'" alt="固定オプション"></p><p><img src="'+k+'" alt="固定オプション"></p>',50)])])}const N=r(T,[["render",S]]);export{D as __pageData,N as default};
